foreach ($registry as $type => $widgets) {
    if (!is_array($widgets)) continue;
    foreach ($widgets as $code => $widget) {
        if (!is_array($widget)) continue;
        if (($widget['module'] ?? '') === $module && ($widget['code'] ?? '') === $code) {
            $widgetMeta = $widget;
            break 2;
        }
    }
}

